if(utcOffset==='UTC+03:00'){const eatCountries=['kenya','tanzania','ethiopia','somalia','uganda','eritrea','djibouti','madagascar'];if(eatCountries.some(function(n){return normalizedCountry.includes(n);})){return'Africa/Nairobi';}
if(normalizedCountry.includes('iraq')){return'Asia/Baghdad';}
if(normalizedCountry.includes('saudi')||normalizedCountry.includes('kuwait')||normalizedCountry.includes('bahrain')||normalizedCountry.includes('qatar')||normalizedCountry.includes('yemen')){return'Asia/Riyadh';}
if(normalizedCountry.includes('russia')||normalizedCountry.includes('moscow')){return'Europe/Moscow';}}
