if(normalizedCountry.includes('queensland')&&utcOffset==='UTC+10:00'){return'Australia/Brisbane';}
if((normalizedCountry.includes('new south wales')||normalizedCountry.includes('victoria'))&&utcOffset==='UTC+10:00'){return'Australia/Sydney';}
if(normalizedCountry.includes('south australia')&&utcOffset==='UTC+09:30'){return'Australia/Adelaide';}
if(normalizedCountry.includes('northern territory')&&utcOffset==='UTC+09:30'){return'Australia/Darwin';}
